import random

# Generate random choice
randOutput = random.choice(['rock','paper','scissors'])
computerChoice = randOutput

""" rock > scissors > paper > rock """
while():
    userChoice = input("Choose rock, paper, or scissors")
    if (userChoice == "rock" & computerChoice == "scissors") or (userChoice == "scissors" & computerChoice == "paper") or (userChoice == "paper" & computerChoice == "rock"):
        print("The winner is: " + userChoice + ". " + userChoice + " beats " + computerChoice)
    elif (computerChoice == "rock" & userChoice == "scissors") or (computerChoice == "scissors" & userChoice == "paper") or (computerChoice == "paper" & userChoice == "rock"):
        print("The winner is: " + computerChoice + ". " + computerChoice + " beats " + userChoice)
    else:
        print("Error. Please enter one of the valid options: rock, paper, or scissors")
